(()=>{
'use strict';
const VERSION='9.0.4';
const FAMILY='default-family';
const LS='ofa-9-data';
const ADMIN_EMAIL='mlehr1211@gmail.com';
let deferredInstall=null,fb=false,uid=localStorage.getItem('ofa-uid')||'local-user',role=localStorage.getItem('ofa-role')||'Family',route='home',selectedTrip=null,unsub=null;
const $=s=>document.querySelector(s);
const id=()=>Date.now().toString(36)+Math.random().toString(36).slice(2,7);
const COLS=['people','trips','memories','media','scrapbooks','meals','grocery','packing','links','reservations','budgets','itinerary','attendees','rsvps','invites','notifications','activity','chats','votes','profiles','settings','locks'];
const blank=()=>({version:VERSION,people:[],trips:[],memories:[],media:[],scrapbooks:[],meals:[],grocery:[],packing:[],links:[],reservations:[],budgets:[],itinerary:[],attendees:[],rsvps:[],invites:[],notifications:[],activity:[],chats:[],votes:[],profiles:[],settings:{theme:'light',adminCode:'1218',notifications:{chat:true,votes:true,trips:true,lists:true,memories:true,admin:true}},locks:{},migrated:false});
let data=load();
function arr(k){ if(!Array.isArray(data[k])) data[k]=[]; return data[k]; }
function st(){data.settings=data.settings||blank().settings;data.settings.adminCode=data.settings.adminCode||'1218';data.settings.notifications=data.settings.notifications||blank().settings.notifications;return data.settings}
function locks(){data.locks=data.locks||{};return data.locks}
function isLocked(area){return !!locks()[area]&&!canAdmin()}
function currentPersonName(){let p=arr('people').find(p=>p.owner===uid||p.email===localStorage.getItem('ofa-email'));return (p&&p.name)|| (canAdmin()?'Melissa':'Family Member')}
function notifyEnabled(kind){return st().notifications[kind]!==false}
function load(){try{return Object.assign(blank(),JSON.parse(localStorage.getItem(LS)||'{}'))}catch{return blank()}}
function save(){migrate(false);data.version=VERSION;localStorage.setItem(LS,JSON.stringify(data));const hasApp=window.firebase&&firebase.apps&&firebase.apps.length;const u=hasApp&&firebase.auth?firebase.auth().currentUser:null;if(fb&&u)firebase.database().ref(`families/${FAMILY}/appData`).set(data).catch(e=>{console.error(e);sync('Saved on this device only');});}
function toast(t){let x=$('#toast'); if(!x) return; x.textContent=t;x.style.display='block';clearTimeout(x._t);x._t=setTimeout(()=>x.style.display='none',3500)}
function sync(t){let x=$('#sync'); if(x)x.textContent=t}
function updateAppBadge(count){try{if('setAppBadge' in navigator){count?navigator.setAppBadge(count):navigator.clearAppBadge()}if(navigator.serviceWorker?.controller)navigator.serviceWorker.controller.postMessage({type:'BADGE_COUNT',count})}catch(e){console.warn('App icon badge unavailable',e)}}
function escape(s=''){return String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}
function canAdmin(){return role==='Admin'}
function setIdentity(u){const who=$('#who'); if(u){uid=u.uid;localStorage.setItem('ofa-uid',uid);localStorage.setItem('ofa-email',u.email||'');let profile=arr('people').find(p=>p.email===(u.email||''));role=(u.email===ADMIN_EMAIL||profile?.role==='Admin')?'Admin':(profile?.role||'Family');localStorage.setItem('ofa-role',role);if(who)who.textContent=(u.email||'Signed in')+' · '+role;}else{uid=localStorage.getItem('ofa-uid')||'local-user';role=localStorage.getItem('ofa-role')||'Family';if(who)who.textContent=(role==='Admin'?'Melissa · Admin (this device)':'Family Member');}}
function canEdit(item={}){return canAdmin()||!item.private||item.owner===uid||item.createdBy===uid}
function migrate(doSave=true){COLS.forEach(k=>{if(['settings','locks'].includes(k)){data[k]=data[k]||blank()[k]}else if(!Array.isArray(data[k]))data[k]=[]});st();locks();arr('trips').forEach(t=>{t.id=t.id||id();t.visibility=t.visibility||'family';t.invitees=t.invitees||[]});['memories','media','scrapbooks','meals','grocery','packing','links','chats','votes'].forEach(k=>arr(k).forEach(x=>{x.id=x.id||id();x.createdAt=x.createdAt||Date.now();x.owner=x.owner||uid}));data.migrated=true;if(doSave)save()}
function activity(text){arr('activity').unshift({id:id(),text,at:Date.now(),user:uid});data.activity=data.activity.slice(0,120);notify(text,false)}
function notify(text,push=true,targetUser=uid){arr('notifications').unshift({id:id(),text,at:Date.now(),read:false,user:targetUser});data.notifications=data.notifications.slice(0,120);updateAppBadge(arr('notifications').filter(n=>(!n.user||n.user===uid)&&!n.read).length);if(push&&'Notification'in window&&Notification.permission==='granted'){try{if(navigator.serviceWorker){navigator.serviceWorker.ready.then(reg=>reg.showNotification('Our Family Adventures',{body:text,icon:'./icons/icon-192.png'})).catch(()=>{});} }catch(e){console.warn('Push display skipped',e)}}save()}
function tripsVisible(){return arr('trips').filter(t=>canAdmin()||t.visibility!=='private'||(t.invitees||[]).includes(uid)||t.owner===uid)}
function byTrip(k){return arr(k).filter(x=>x&&(!selectedTrip||x.tripId===selectedTrip)).filter(x=>!x.private||canAdmin()||x.owner===uid)}
function trip(){return arr('trips').find(t=>t.id===selectedTrip)||tripsVisible()[0]}
function peopleOptions(){let p=arr('people');return p.length?p.map(x=>x.name||x.email||'Family member'):['Melissa','Everyone']}
function assignmentEditor(entity,item){let assigned=Array.isArray(item.assignedTo)?item.assignedTo:(item.assignedTo?[item.assignedTo]:[]);return `<div class="assignmentEditor"><b>Who is bringing / responsible?</b>${peopleOptions().map(name=>`<label><input type="checkbox" ${assigned.includes(name)?'checked':''} onchange="app.toggleAssignment('${entity}','${item.id}',${JSON.stringify(name)})"> ${escape(name)}</label>`).join('')}</div>`}
function tripPreview(kind){let rows=byTrip(kind);if(!rows.length)return '<p class="muted">Nothing added yet.</p>';if(kind==='media'){return `<div class="tripMediaThumbs">${rows.slice(0,8).map(x=>x.url?`<button class="tripMediaThumb" onclick="app.go('media','${escape(x.tripId||selectedTrip||'')}')" aria-label="Open media"><img src="${escape(x.url)}" alt="${escape(x.name||'Trip photo')}"></button>`:'').join('')}${rows.length>8?`<small>+ ${rows.length-8} more</small>`:''}</div>`}return `<div class="tripPreview">${rows.slice(0,4).map(x=>{let title=x.name||x.type||x.title||x.category||x.description||'Item';let extra=x.day||x.date||x.amount||x.time||x.status||'';return `<div><b>${escape(title)}</b>${extra?`<small>${escape(extra)}</small>`:''}</div>`}).join('')}${rows.length>4?`<small>+ ${rows.length-4} more</small>`:''}</div>`}
function weatherMarkup(){return `<div id="tripWeather" class="weatherPanel"><p class="muted">Loading live weather for ${escape(trip()?.location||trip()?.name||'trip destination')}…</p></div>`}
function setRoute(r,arg){route=r;if(arg)selectedTrip=arg;location.hash=arg?`${r}/${arg}`:r;render()}
function parseHash(){let h=(location.hash||'#home').slice(1).split('/');route=h[0]||'home';if(h[1])selectedTrip=h[1]}
function enter(){localStorage.setItem('ofa-entered','yes');$('#splash')?.classList.add('hidden');$('#shell')?.classList.remove('hidden');render()}
function initFirebase(){try{setIdentity(null);if(!window.firebase||!window.firebaseConfig||!firebaseConfig.apiKey){sync('Local admin saving ready');return}if(!firebase.apps.length)firebase.initializeApp(firebaseConfig);sync('Firebase ready · sign in for family sync');firebase.auth().onAuthStateChanged(u=>{if(!u){fb=false;setIdentity(null);sync('Admin on this device · sign in for family sync');render();return}uid=u.uid;fb=true;setIdentity(u);sync('Connected and saving');const ref=firebase.database().ref(`families/${FAMILY}/appData`);if(unsub)ref.off('value',unsub);unsub=ref.on('value',snap=>{if(snap.exists()){data=Object.assign(blank(),snap.val());localStorage.setItem(LS,JSON.stringify(data));migrate(false);render()}else save()});});}catch(e){console.error(e);setIdentity(null);sync('Local admin saving ready')}}
function setup(){window.addEventListener('error',e=>{try{const m=String(e.message||'');const src=String(e.filename||'');const generic=!m||m==='Script error.'||m==='Script error';const external=src&&new URL(src,location.href).origin!==location.origin;if(generic||external||m.includes('Illegal constructor')||(m.includes('Unexpected end of input')&&!src.includes('app.js'))){console.warn('Non-app script error ignored',{message:m,source:src});return}console.error('Application error',e.error||e);sync('Startup issue: '+m)}catch(err){console.warn('Error handler skipped',err)}});window.addEventListener('unhandledrejection',e=>{const reason=e.reason;const m=String(reason?.message||reason||'');if(!m||/network|failed to fetch|permission|popup|notification/i.test(m)){console.warn('Background request issue',reason);return}console.error('Unhandled application promise',reason);sync('Startup issue: '+m)});sync('Admin on this device · local saving ready');parseHash();if(localStorage.getItem('ofa-entered'))enter();window.addEventListener('hashchange',()=>{parseHash();render()});window.addEventListener('beforeinstallprompt',e=>{e.preventDefault();deferredInstall=e});if('serviceWorker'in navigator)navigator.serviceWorker.register('./service-worker.js').catch(()=>{});let mb=$('#menuBtn'); if(mb)mb.onclick=()=>$('#drawer')?.classList.toggle('open');migrate(false);initFirebase();setTimeout(()=>{if($('#sync')?.textContent?.includes('Starting'))sync('Admin on this device · local saving ready')},1200)}
function nav(){let dock=$('#dock'),drawer=$('#drawer');if(!dock||!drawer)return;let n=[['🏠','Home','home'],['🔐','Login','login'],['🧳','Trips','trips'],['🖼️','Media','media'],['📖','Scrapbook','scrapbook'],['✅','Lists','lists'],['💬','Chat','chat'],['⚙️','Settings','settings']];if(canAdmin())n.push(['🛡️','Admin','admin']);dock.innerHTML=n.map(x=>`<button onclick="app.go('${x[2]}')"><span>${x[0]}</span>${x[1]}</button>`).join('');let pages=['home','login','trips','people','media','memories','scrapbook','meals','grocery','packing','links','voting','analytics','chat','messages','settings','history','notifications','assignments'];if(canAdmin())pages.push('admin');drawer.innerHTML='<h2>Menu</h2>'+pages.map(r=>`<button onclick="app.go('${r}');document.querySelector('#drawer').classList.remove('open')">${r[0].toUpperCase()+r.slice(1)}</button>`).join('')+'<button onclick="app.exportData()">Download Backup</button><button onclick="app.importClick()">Import/Migrate Backup</button><input id="importFile" type="file" accept="application/json" class="hidden">'}
function render(){migrate(false);document.body.classList.toggle('dark',st().theme==='dark');nav();let unread=arr('notifications').filter(n=>(!n.user||n.user===uid)&&!n.read).length;let badge=$('#badge'); if(badge)badge.textContent=unread;updateAppBadge(unread);let view=$('#view'); if(!view)return;if(route==='admin'&&!canAdmin())route='home';view.innerHTML=(views[route]||views.home)()+floatingChat(); if(route==='scrapbook') setTimeout(drawScrap,50); if(route==='trip'||route==='weather') setTimeout(loadTripWeather,80); setTimeout(makeFloatingChatMoveable,50)}
function card(title,body,cls=''){return `<section class="card ${cls}"><h2>${title}</h2>${body}</section>`}
function form(entity,fields,tripScoped=false){let inputs=fields.map(f=>{if(f.type==='area')return `<textarea id="f_${f.k}" placeholder="${f.l}"></textarea>`; if(f.type==='select')return `<select id="f_${f.k}">${(f.options||[]).map(o=>`<option value="${escape(o.v||o)}">${escape(o.l||o)}</option>`).join('')}</select>`; if(f.type==='people')return `<div class="checks"><b>${escape(f.l)}</b>${peopleOptions().map(p=>`<label><input type="checkbox" name="f_${f.k}" value="${escape(p)}"> ${escape(p)}</label>`).join('')}</div>`; return `<input id="f_${f.k}" type="${f.type||'text'}" placeholder="${f.l}">`}).join('');return `<div class="formgrid">${inputs}</div><button class="primary" onclick='app.add("${entity}",${JSON.stringify(fields.map(f=>f.k))},${tripScoped})'>Add / Save</button>`}
function list(entity,items,fmt,allowDelete=true){items=Array.isArray(items)?items:[];return `<div class="list">${items.length?items.map(x=>`<div class="item"><div class="between row"><div>${fmt(x)}</div><div class="row">${allowDelete&&canEdit(x)?`<button onclick="app.del('${entity}','${x.id}')">Delete</button>`:''}</div></div></div>`).join(''):'<p class="muted">Nothing added yet.</p>'}</div>`}
function tripPicker(){let ts=tripsVisible();if(!selectedTrip&&ts[0])selectedTrip=ts[0].id;return `<select onchange="app.pickTrip(this.value)">${ts.map(t=>`<option ${t.id===selectedTrip?'selected':''} value="${t.id}">${escape(t.name||'Trip')}</option>`).join('')}</select>`}
function selectedTripDates(){let t=trip(); if(!t||!t.start||!t.end)return ['']; let out=[],d=new Date(t.start+'T00:00:00'),end=new Date(t.end+'T00:00:00'); for(let i=0; d<=end && i<45; i++,d.setDate(d.getDate()+1)){out.push(d.toLocaleDateString(undefined,{weekday:'long',month:'short',day:'numeric',year:'numeric'}));} return out;}
function featureTabs(){let t=trip();if(!t)return '';return `<div class="navtabs">${['trip','meals','grocery','packing','links','rsvp','reservations','budget','weather','maps','itinerary','attendees','chat','memories','media','scrapbook'].map(r=>`<button onclick="app.go('${r}','${t.id}')">${r}</button>`).join('')}</div>`}
function recent(){return card('Recent Activity',list('activity',arr('activity').slice(0,8),a=>`<b>${escape(a.text)}</b><p class="muted">${new Date(a.at).toLocaleString()}</p>`,false))}
function floatingChat(){if(route==='chat')return '';let msgs=byTrip('chats').concat(arr('chats').filter(c=>!c.tripId)).slice(0,20);return `<div id="quickChat" class="quickChat hidden"><div class="quickChatHead"><b>Family Chat</b><button onclick="app.toggleQuickChat()">×</button></div><div class="quickChatFeed">${msgs.map(c=>`<div class="quickMsg"><b>${escape(c.userName||'Family')}</b><span>${escape(c.text)}</span><small>${new Date(c.createdAt).toLocaleTimeString([], {hour:'numeric',minute:'2-digit'})}</small></div>`).join('')||'<p class="muted">No messages yet.</p>'}</div><div class="quickChatSend"><input id="quickChatText" placeholder="Message the family"><button class="primary" onclick="app.sendQuickChat()">Send</button></div><button class="openFullChat" onclick="app.go('chat')">Open full chat</button></div><button id="floatChat" class="chat floatChat" aria-label="Open family chat">💬</button>`}
function makeFloatingChatMoveable(){let b=$('#floatChat');if(!b)return;let pos={};try{pos=JSON.parse(localStorage.getItem('ofa-chat-pos')||'{}')}catch{}if(Number.isFinite(pos.x)&&Number.isFinite(pos.y)){b.style.left=pos.x+'px';b.style.top=pos.y+'px';b.style.right='auto';b.style.bottom='auto'}let start=null;b.onpointerdown=e=>{start={x:e.clientX,y:e.clientY,l:b.offsetLeft,t:b.offsetTop,moved:false};b.setPointerCapture(e.pointerId);e.preventDefault()};b.onpointermove=e=>{if(!start)return;let dx=e.clientX-start.x,dy=e.clientY-start.y;if(Math.abs(dx)+Math.abs(dy)>8)start.moved=true;if(start.moved){b.style.left=Math.max(8,Math.min(innerWidth-b.offsetWidth-8,start.l+dx))+'px';b.style.top=Math.max(72,Math.min(innerHeight-b.offsetHeight-90,start.t+dy))+'px';b.style.right='auto';b.style.bottom='auto'}};b.onpointerup=e=>{let moved=start?.moved;if(moved)localStorage.setItem('ofa-chat-pos',JSON.stringify({x:b.offsetLeft,y:b.offsetTop}));start=null;if(!moved)toggleQuickChat()};}
function toggleQuickChat(){let q=$('#quickChat');if(!q)return;q.classList.toggle('hidden');if(!q.classList.contains('hidden'))setTimeout(()=>$('#quickChatText')?.focus(),50)}
function sendQuickChat(){let text=$('#quickChatText')?.value?.trim();if(!text)return;arr('chats').unshift({id:id(),tripId:selectedTrip||'',text,user:uid,userName:currentPersonName(),createdAt:Date.now()});save();notify('New group chat message');render();setTimeout(()=>$('#quickChat')?.classList.remove('hidden'),30)}
const views={
login(){return card('Admin Login / Family Sync',`<p>You are already opened as <b>Admin on this device</b>. Use this page to connect the app to Firebase so it saves for all family members.</p><div class="formgrid"><input id="loginEmail" type="email" placeholder="Email" value="mlehr1211@gmail.com"><input id="loginPass" type="password" placeholder="Password"></div><div class="row"><button class="primary" onclick="app.signIn()">Sign In</button><button onclick="app.signUpAdmin()">Create Admin Login</button><button onclick="app.signOut()">Sign Out</button></div><p class="muted">If Firebase says the sign-in method is disabled, enable Email/Password in Firebase Authentication. Until then, the app still saves on this device as Admin.</p>`)},
home(){let next=tripsVisible()[0];return `<section class="welcomeHero"><img src="./assets/lighthouse-home.png" alt="Lighthouse"><div><h1>Making Memories Together</h1><p>Plan every family adventure in one beautiful, shared place.</p>${next?`<button class="primary" onclick="app.go('trip','${next.id}')">Open ${escape(next.name)}</button>`:`<button class="primary" onclick="app.go('trips')">Plan an Adventure</button>`}</div></section><div class="grid homeTiles">${['trips','people','chat','media','scrapbook','notifications'].map(x=>`<div class="card tile" onclick="app.go('${x}')"><h3>${x[0].toUpperCase()+x.slice(1)}</h3><p>Open ${x}</p></div>`).join('')}</div>`},
people(){return card('People / Profiles',`<p class="muted">Family members can update their contact info and change their profile photo.</p><div class="formgrid"><input id="f_name" placeholder="Name"><input id="f_email" type="email" placeholder="Email"><input id="f_phone" placeholder="Phone"><input id="profilePhoto" type="file" accept="image/*"></div><button class="primary" onclick="app.addProfile()">Add / Save Profile</button>`+list('people',arr('people'),p=>`${p.photo?`<img src="${escape(p.photo)}" class="avatar">`:''}<b>${escape(p.name)}</b><p class="muted">${escape(p.email||'')} ${escape(p.phone||'')}</p><div class="row"><button onclick="app.editProfile('${p.id}')">Edit Info</button><label class="buttonLike">Change Photo<input class="hidden" type="file" accept="image/*" onchange="app.changeProfilePhoto('${p.id}',this.files[0])"></label></div>`))},
trips(){return card('Trips',form('trips',[{k:'name',l:'Trip name'},{k:'location',l:'Destination / address'},{k:'start',l:'Arrival date',type:'date'},{k:'end',l:'Departure date',type:'date'},{k:'visibility',l:'Visibility',type:'select',options:['family','private']}])+list('trips',tripsVisible(),t=>`<b>${escape(t.name)}</b><p class="muted">${escape(t.location||'No location')} · ${escape(t.start||'')} ${t.end?'to '+escape(t.end):''}</p><button class="primary" onclick="app.go('trip','${t.id}')">Open dedicated trip page</button>`))},
trip(){let t=trip();if(!t)return views.trips();let q=encodeURIComponent(t.location||t.name||'');let modules=[['meals','meals'],['grocery','grocery'],['packing','packing'],['links','links'],['rsvp','rsvps'],['reservations','reservations'],['budget','budgets'],['itinerary','itinerary'],['attendees','attendees'],['memories','memories'],['media','media'],['scrapbook','scrapbooks']];return featureTabs()+card(escape(t.name||'Trip'),`<p class="muted">${escape(t.location||'Add a trip destination')}</p><div class="tripHeroGrid"><iframe class="map" loading="lazy" src="https://www.google.com/maps?q=${q}&output=embed"></iframe>${weatherMarkup()}</div><div class="grid tripModuleGrid">${modules.map(([r,k])=>`<div class="card tripModule"><div class="between row"><h3>${r[0].toUpperCase()+r.slice(1)}</h3><button onclick="app.go('${r}','${t.id}')">Open</button></div>${tripPreview(k)}</div>`).join('')}<div class="card tripModule"><div class="between row"><h3>Weather</h3><button onclick="app.go('weather','${t.id}')">Open</button></div>${weatherMarkup()}</div><div class="card tripModule"><div class="between row"><h3>Maps</h3><button onclick="app.go('maps','${t.id}')">Open</button></div><p class="muted">${escape(t.location||'Destination not added')}</p></div></div>`)},
meals(){let dates=selectedTripDates();return featureTabs()+card('Meal Planning',tripPicker()+`<h3>Meal list</h3>`+list('meals',byTrip('meals'),m=>`<b>${escape(m.day)} · ${escape(m.type)}</b><p>${escape(m.name||'')}</p><p class="muted">${escape(m.address||'')} ${m.time?' · '+escape(m.time):''} ${m.url?` · <a href="${escape(m.url)}" target="_blank" rel="noopener">Open link</a>`:''}</p><p class="muted">Bringing / attending: ${escape(Array.isArray(m.assignedTo)?(m.assignedTo.join(', ')||'Open'):m.assignedTo||'Open')}</p>${assignmentEditor('meals',m)}`)+`<h3 class="addHead">Add another meal</h3>`+form('meals',[{k:'day',l:'Trip date',type:'select',options:dates},{k:'type',l:'Meal type',type:'select',options:['Breakfast','Lunch','Dinner','Snacks','Happy Hour','Dining Out']},{k:'name',l:'Meal / restaurant name'},{k:'address',l:'Restaurant address'},{k:'url',l:'Restaurant link / reservation URL'},{k:'time',l:'Meeting time',type:'time'},{k:'assignedTo',l:'Assigned to',type:'people'}],true))},
grocery(){return featureTabs()+card('Grocery Lists',tripPicker()+`<h3>Grocery list</h3>`+list('grocery',byTrip('grocery'),g=>`<label class="bigcheck"><input type="checkbox" ${g.done?'checked':''} onchange="app.toggleDone('grocery','${g.id}')"> <b>${escape(g.name)}</b></label><p class="muted">${escape(g.qty||'')} · Assigned: ${escape(Array.isArray(g.assignedTo)?(g.assignedTo.join(', ')||'Open'):g.assignedTo||'Open')} ${g.private?'· Private':''}</p>${assignmentEditor('grocery',g)}`)+`<h3 class="addHead">Add another grocery item</h3>`+form('grocery',[{k:'name',l:'Item'},{k:'qty',l:'Quantity'},{k:'assignedTo',l:'Assigned to',type:'people'},{k:'private',l:'Private?',type:'select',options:[{v:'',l:'Shared'},{v:'yes',l:'Private'}]}],true))},
packing(){return featureTabs()+card('Packing Lists',tripPicker()+`<h3>Packing list</h3>`+list('packing',byTrip('packing'),p=>`<label class="bigcheck"><input type="checkbox" ${p.done?'checked':''} onchange="app.toggleDone('packing','${p.id}')"> <b>${escape(p.name)}</b></label><p class="muted">Assigned: ${escape(Array.isArray(p.assignedTo)?(p.assignedTo.join(', ')||'Open'):p.assignedTo||'Open')} ${p.private?'· Private':''}</p>${assignmentEditor('packing',p)}`)+`<h3 class="addHead">Add another packing item</h3>`+form('packing',[{k:'name',l:'Packing item'},{k:'assignedTo',l:'Assigned to',type:'people'},{k:'private',l:'Private?',type:'select',options:[{v:'',l:'Shared'},{v:'yes',l:'Private'}]}],true))},
links(){return featureTabs()+card('Travel Links',tripPicker()+form('links',[{k:'name',l:'Travel link name'},{k:'url',l:'URL'},{k:'address',l:'Address'},{k:'type',l:'Type',type:'select',options:['Lodging','Restaurant','Activity','Reservation','Map','Other']}],true)+list('links',byTrip('links'),l=>`<b>${escape(l.name)}</b><p class="muted">${escape(l.type||'Link')} ${escape(l.address||'')}</p>${l.url?`<a href="${escape(l.url)}" target="_blank" rel="noopener">Open link</a>`:''}`))},
	rsvp(){let rows=byTrip('rsvps'),opts=["Attending","Maybe","Can't Attend"];return featureTabs()+card('RSVP',tripPicker()+`<p class="muted">Choose one response. Changing your RSVP updates your existing response.</p><div class="grid">${opts.map(o=>{let names=rows.filter(r=>r.status===o).map(r=>r.name);return `<div class="card"><h3>${o}</h3><strong>${names.length}</strong><p>${names.map(escape).join(', ')||'No responses yet'}</p><button class="primary" data-status="${escape(o)}" onclick="app.setRsvp(this.dataset.status)">Choose ${o}</button></div>`}).join('')}</div>`)},
	reservations(){return featureTabs()+card('Reservations',tripPicker()+form('reservations',[{k:'name',l:'Reservation name'},{k:'date',l:'Date',type:'date'},{k:'time',l:'Time',type:'time'},{k:'confirmation',l:'Confirmation number'},{k:'url',l:'Reservation link'}],true)+list('reservations',byTrip('reservations'),x=>`<b>${escape(x.name)}</b><p>${escape(x.date||'')} ${escape(x.time||'')}</p><p class="muted">${escape(x.confirmation||'')}</p>${x.url?`<a href="${escape(x.url)}" target="_blank">Open</a>`:''}`))},
	budget(){let rows=byTrip('budgets'),total=rows.reduce((a,x)=>a+Number(x.amount||0),0);return featureTabs()+card('Budget',tripPicker()+`<h3>Total: $${total.toFixed(2)}</h3>`+form('budgets',[{k:'name',l:'Expense'},{k:'amount',l:'Amount',type:'number'},{k:'paidBy',l:'Paid by',type:'people'},{k:'notes',l:'Notes'}],true)+list('budgets',rows,x=>`<b>${escape(x.name)}</b><p>$${Number(x.amount||0).toFixed(2)}</p><p class="muted">Paid by ${escape(Array.isArray(x.paidBy)?x.paidBy.join(', '):x.paidBy||'')}</p>`))},
	weather(){let t=trip();return featureTabs()+card('Live Weather',weatherMarkup()+`<p class="muted">Automatically using ${escape(t?.location||t?.name||'trip destination')}.</p>`)},
	maps(){let t=trip(),q=encodeURIComponent(t?.location||t?.name||'');return featureTabs()+card('Maps',`<iframe class="map mapFull" src="https://www.google.com/maps?q=${q}&output=embed"></iframe><p><a class="buttonLike" target="_blank" href="https://www.google.com/maps/search/?api=1&query=${q}">Open directions</a></p>`)},
	itinerary(){return featureTabs()+card('Itinerary',tripPicker()+form('itinerary',[{k:'date',l:'Date',type:'date'},{k:'time',l:'Time',type:'time'},{k:'name',l:'Activity'},{k:'location',l:'Location'},{k:'notes',l:'Notes'}],true)+list('itinerary',byTrip('itinerary'),x=>`<b>${escape(x.date)} ${escape(x.time||'')} · ${escape(x.name)}</b><p>${escape(x.location||'')}</p><p class="muted">${escape(x.notes||'')}</p>`))},
	attendees(){return featureTabs()+card('Attendees',tripPicker()+form('attendees',[{k:'people',l:'Select attendees',type:'people'}],true)+list('attendees',byTrip('attendees'),x=>`<b>${escape(Array.isArray(x.people)?x.people.join(', '):x.people||'')}</b>`))},
memories(){return featureTabs()+card('Memories',tripPicker()+`<div class="formgrid"><input id="memTitle" placeholder="Memory title"><input id="memDate" type="date"><textarea id="memText" placeholder="Journal entry"></textarea><input id="memFiles" type="file" multiple accept="image/*,video/*"></div><button class="primary" onclick="app.addMemory()">Save Memory with Photos</button>`+list('memories',byTrip('memories'),m=>`${(m.photos||[]).map(u=>`<img src="${escape(u)}" style="max-width:100px;border-radius:12px;margin:4px">`).join('')}<b>${escape(m.title)}</b><p>${escape(m.text||'')}</p><p class="muted">${escape(m.date||'')}</p>`))},
media(){return featureTabs()+card('Media Library',tripPicker()+`<input id="mediaFile" type="file" multiple accept="image/*,video/*"><button class="primary" onclick="app.uploadMedia()">Add Media</button>`+list('media',byTrip('media'),m=>`${m.url?`<img src="${escape(m.url)}" style="max-width:120px;border-radius:12px">`:''}<b>${escape(m.name||'Media')}</b><p class="muted">${escape(m.type||'')}</p>${m.url?`<a download="${escape(m.name||'family-photo')}" href="${escape(m.url)}">Download</a>`:''}`))},
scrapbook(){let photos=byTrip('media').filter(m=>m.url&&String(m.type||'').startsWith('image'));return featureTabs()+card('Scrapbook Studio',tripPicker()+`<p class="muted">The page is a fixed canvas. Photos, text, stickers and emojis stay exactly where you place them when saved.</p><div class="scrapTools"><select id="scrapBg" onchange="app.setScrapBg(this.value)"><option value="seaglass">Sea glass</option><option value="dustyrose">Dusty rose</option><option value="greenery">Greenery</option><option value="rosegold">Rose gold</option><option value="sunset">Sunset</option><option value="sand">Sand</option><option value="lighthouse">Lighthouse</option><option value="beach">Beach</option><option value="mountains">Mountains</option><option value="camping">Camping</option><option value="party">Party</option><option value="happy">Happy Hour</option><option value="city">City Life</option></select><select id="scrapFrame" onchange="app.applyFrame(this.value)"><option value="nofill">No frame</option><option value="soft">Simple outline</option><option value="polaroid">Polaroid</option><option value="gold">Classic border</option><option value="shell">Dotted outline</option></select><select id="scrapCutout" onchange="app.applyCutout(this.value)"><option value="none">No cutout</option><option value="heart">Heart cutout</option><option value="scallop">Scalloped cutout</option><option value="flower">Flower cutout</option></select><label class="colorPick">Frame color <input id="scrapFrameColor" type="color" value="#d8b46a" onchange="app.applyFrameColor(this.value)"></label><select id="scrapLayout" onchange="app.applyLayout(this.value)"><option value="freeform">Freeform</option><option value="grid2">2-photo grid</option><option value="grid4">4-photo grid</option><option value="collage">Layered collage</option><option value="feature">Feature photo</option></select><button onclick="app.applyLayout(document.querySelector('#scrapLayout').value)">Apply Layout</button><button onclick="app.addScrapText()">Add Text</button><button onclick="app.addCollage()">Quick 4-photo Collage</button><button onclick="app.saveScrapbook()" class="primary">Save / Finalize Page</button><button onclick="app.exportScrapPDF()">Export PDF</button></div><h3>Select photos</h3><div class="photoPicker">${photos.length?photos.map(m=>`<label><input type="checkbox" name="scrapPhoto" value="${escape(m.id)}"><img src="${escape(m.url)}" alt="${escape(m.name||'Photo')}"><span>${escape(m.name||'Photo')}</span></label>`).join(''):'<p class="muted">Add photos in Media first.</p>'}</div><button onclick="app.addSelectedPhoto()">Add Selected Photos</button><div class="scrapTools stickers">${['⭐','😀','😂','😍','❤️','🎉','🏖️','🌊','⛰️','🏕️','🍹','🍻','🍽️','🚗','🏙️','🧭','🧳','🏍️','🛶','🐟','🔥','🌸','☀️','🌙'].map(e=>`<button onclick="app.addSticker('${e}')">${e}</button>`).join('')}</div><div class="scrapTools"><button onclick="app.zoomPhoto(1.12)">Zoom +</button><button onclick="app.zoomPhoto(.88)">Zoom -</button><button onclick="app.cropPhoto()">Crop / Fit</button><button onclick="app.rotatePhoto()">Rotate</button><button onclick="app.bringForward()">Bring Forward</button><button onclick="app.sendBackward()">Send Backward</button><button onclick="app.deleteScrapObject()">Delete Selected</button></div><div class="canvasWrap fixedCanvasWrap"><div id="scrapCanvas" class="scrapCanvas seaglass trueLayout"></div></div><h3>Finalized scrapbook pages</h3>`+list('scrapbooks',byTrip('scrapbooks'),s=>`<b>${escape(s.title||'Scrapbook page')}</b><p class="muted">${new Date(s.createdAt).toLocaleString()} · finalized/locked</p>${savedScrapMarkup(s)}`))},
voting(){return featureTabs()+card('Family Voting',tripPicker()+`<h3>Current voting options</h3>`+list('votes',byTrip('votes'),v=>`<b>${escape(v.category)}: ${escape(v.name)}</b><p class="muted">${escape(v.address||'')} ${v.url?` · <a href="${escape(v.url)}" target="_blank">Open link</a>`:''}</p><button onclick="app.castVote('${v.id}')">Vote / Change My Vote</button><p class="muted">Voted: ${(v.voters||[]).join(', ')||'No one yet'}</p>`)+`<h3>Add another voting option</h3>`+form('votes',[{k:'category',l:'Vote type',type:'select',options:['Dates','Location','Lodging','Activity','Restaurant']},{k:'name',l:'Voting option'},{k:'url',l:'Link for this option'},{k:'address',l:'Address / notes'}],true)+`<p><button onclick="app.go('analytics')">Open Voting Analytics</button></p>`)},
chat(){return featureTabs()+card('Live Group Chat',`<p class="muted">Messages sync live for signed-in family members. Use the floating chat bubble from any page.</p><div class="chatBox">${byTrip('chats').concat(arr('chats').filter(c=>!c.tripId)).slice(0,80).map(c=>`<div class="chatMsg"><b>${escape(c.userName||'Family')}</b><p>${escape(c.text)}</p><small>${new Date(c.createdAt).toLocaleString()}</small>${canAdmin()?` <button onclick="app.del('chats','${c.id}')">Delete</button>`:''}</div>`).join('')}</div><div class="row"><input id="chatText" placeholder="Message the family"><button class="primary" onclick="app.sendChat()">Send</button></div><p class="muted">Admin can delete old chat messages when the conversation gets too long.</p>` )},
lists(){return `<div class="grid">${['meals','grocery','packing','assignments','links','voting','chat'].map(x=>`<div class="card tile" onclick="app.go('${x}')"><h2>${x}</h2><p>Open ${x} page.</p></div>`).join('')}</div>`},
history(){return card('Trip History Map',`<p class="muted">Completed trips with locations become family adventure pins.</p><iframe class="map" src="https://www.google.com/maps?q=${encodeURIComponent(arr('trips').map(t=>t.location).filter(Boolean).join('|')||'United States')}&output=embed"></iframe>`+list('trips',arr('trips').filter(t=>t.location),t=>`📍 <b>${escape(t.name)}</b><p class="muted">${escape(t.location)}</p>`,false))},
notifications(){let mine=arr('notifications').filter(n=>!n.user||n.user===uid);return card('My Notifications',`<div class="row"><button onclick="app.markRead()">Mark my notifications read</button><button class="danger" onclick="app.clearMyNotifications()">Clear my notifications</button></div><p class="muted">Only your notification history is shown and changed here.</p>`+list('notifications',mine,n=>`<b>${escape(n.text)}</b><p class="muted">${new Date(n.at).toLocaleString()} ${n.read?'· read':'· unread'}</p>`,false))},

assignments(){let name=currentPersonName();let rows=[...byTrip('meals').map(x=>({...x,_kind:'Meal'})),...byTrip('grocery').map(x=>({...x,_kind:'Grocery'})),...byTrip('packing').map(x=>({...x,_kind:'Packing'}))].filter(x=>{let a=Array.isArray(x.assignedTo)?x.assignedTo:(x.assignedTo?[x.assignedTo]:[]);return canAdmin()||a.includes(name)});return featureTabs()+card('Assignments',tripPicker()+`<p class="muted">A combined responsibility view. Grocery and packing remain separate in their own lists.</p>`+list('assignments',rows,x=>`<b>${escape(x._kind)} · ${escape(x.name||x.type||'Item')}</b><p class="muted">${escape(x.day||'')} ${escape(x.time||'')} · ${escape((Array.isArray(x.assignedTo)?x.assignedTo.join(', '):x.assignedTo)||'Open')}</p>`,false))},
settings(){let n=st().notifications;let perm=('Notification'in window)?Notification.permission:'unsupported';return card('Settings',`<p>Each family member can choose notification categories and display theme.</p><div class="notificationPermission"><b>Phone notifications: ${escape(perm)}</b><p class="muted">Tap Enable Notifications on each phone or tablet that should receive alerts.</p><button class="primary" onclick="app.requestPush()">Enable Notifications</button></div><div class="settingsGrid"><label><input type="checkbox" ${st().theme==='dark'?'checked':''} onchange="app.setTheme(this.checked?'dark':'light')"> Use dark theme</label>${['chat','votes','trips','lists','memories','admin'].map(k=>`<label><input type="checkbox" ${n[k]!==false?'checked':''} onchange="app.setNotify('${k}',this.checked)"> ${k[0].toUpperCase()+k.slice(1)} notifications</label>`).join('')}</div>`)},
analytics(){let rows=byTrip('votes');let cats=[...new Set(rows.map(v=>v.category||'General'))];return featureTabs()+card('Voting Analytics',tripPicker()+cats.map(cat=>`<h3>${escape(cat)}</h3>`+list('votes',rows.filter(v=>v.category===cat),v=>`<b>${escape(v.name)}</b><p class="muted">${(v.voters||[]).length} vote(s): ${(v.voters||[]).map(escape).join(', ')||'No votes yet'}</p>`,false)).join(''))},
messages(){return card('Group Text / Email',`<p>Select family members to send a private group text or email. This opens your phone's text/email app with the selected contacts.</p><div class="checks"><b>Recipients</b>${arr('people').map(p=>`<label><input type="checkbox" name="msgPeople" value="${escape(p.id)}"> ${p.photo?`<img src="${escape(p.photo)}" class="miniAvatar">`:''}${escape(p.name||p.email||'Family')}</label>`).join('')||'<p class="muted">Add profiles first.</p>'}</div><textarea id="msgBody" placeholder="Message"></textarea><div class="row"><button class="primary" onclick="app.sendGroupText()">Open Group Text</button><button onclick="app.sendGroupEmail()">Open Group Email</button></div>`)},
admin(){return canAdmin()?card('Admin Dashboard',`<div class="notice card"><b>Version ${VERSION}</b><p>Admin tools for invites, migration, duplicate prevention, activity cleanup, chat cleanup, push notifications, and backups.</p></div><div class="grid"><div>${form('invites',[{k:'email',l:'Invite email'},{k:'name',l:'Name'},{k:'role',l:'Role',type:'select',options:['Admin','Family','Guest','Child']}])}</div><div class="card"><h3>Tools</h3><button onclick="app.dedupe()">Remove Duplicates</button><button onclick="app.clearActivity()">Clear Activity Log</button><button onclick="app.clearChat()">Clear Chat</button><button onclick="app.requestPush()">Enable Push Notifications</button><button onclick="app.exportData()">Download Backup</button><button onclick="app.migrateNow()">Run Migration</button></div><div class="card"><h3>Admin Code</h3><p class="muted">Default code is 1218.</p><input id="newAdminCode" type="password" placeholder="New admin code"><button onclick="app.changeAdminCode()">Change Admin Code</button></div><div class="card"><h3>Admin Locks</h3>${['trips','meals','grocery','packing','links','voting','chat','media','memories','scrapbook'].map(a=>`<label><input type="checkbox" ${locks()[a]?'checked':''} onchange="app.toggleLock('${a}')"> Lock ${a}</label>`).join('')}</div></div>`+list('invites',arr('invites'),i=>`<b>${escape(i.email)}</b><p class="muted">${escape(i.role)} · code ${escape(i.code||'')}</p>`)+recent()):card('Admin Only','<p>This area is only visible to admins.</p>')}
};
function readPeopleChecks(k){return [...document.querySelectorAll(`input[name="f_${k}"]:checked`)].map(x=>x.value)}
function add(entity,keys,tripScoped){if(isLocked(entity)){toast('This area is locked by Admin');return}let obj={id:id(),createdAt:Date.now(),owner:uid};keys.forEach(k=>{let checks=document.querySelectorAll(`input[name="f_${k}"]`);obj[k]=checks.length?readPeopleChecks(k):($(`#f_${k}`)||{}).value||''});if(tripScoped)obj.tripId=selectedTrip||((tripsVisible()[0]||{}).id);if(entity==='invites')obj.code=(Math.random().toString(36).slice(2,8)).toUpperCase();if(obj.private==='yes')obj.private=true;else delete obj.private;if(Array.isArray(obj.assignedTo)&&!obj.assignedTo.length)obj.assignedTo=[];let dupe=arr(entity).some(x=>keys.every(k=>(x[k]||'')===(obj[k]||''))&&(x.tripId||'')===(obj.tripId||''));if(dupe){toast('Duplicate prevented');return}arr(entity).unshift(obj);save();activity(`Added ${entity.replace(/s$/,'')}`);keys.forEach(k=>{let el=$(`#f_${k}`);if(el)el.value='';document.querySelectorAll(`input[name="f_${k}"]`).forEach(c=>c.checked=false)});render()}
function del(entity,itemId){if(!canAdmin()&&entity==='activity'){toast('Only Admin can delete activity');return}if(!confirm('Delete this item?'))return;data[entity]=arr(entity).filter(x=>x.id!==itemId);save();activity(`Deleted ${entity} item`);render()}
function dedupe(){let count=0;COLS.forEach(k=>{let seen=new Set();data[k]=arr(k).filter(x=>{let sig=JSON.stringify([x.tripId,x.name,x.title,x.url,x.email,x.day,x.type,x.text]);if(seen.has(sig)){count++;return false}seen.add(sig);return true})});save();toast(`Removed ${count} duplicates`);render()}
function fileToDataURL(f){return new Promise(res=>{let r=new FileReader();r.onload=()=>res(r.result);r.readAsDataURL(f)})}
async function uploadOne(f,prefix='media'){let obj={id:id(),tripId:selectedTrip,owner:uid,name:f.name,type:f.type,createdAt:Date.now()};if(fb&&window.firebase&&firebase.storage){let path=`families/${FAMILY}/${prefix}/${obj.id}-${f.name}`;let snap=await firebase.storage().ref(path).put(f);obj.url=await snap.ref.getDownloadURL()}else obj.url=await fileToDataURL(f);return obj}
async function uploadMedia(){let files=[...($('#mediaFile')?.files||[])];for(const f of files){arr('media').unshift(await uploadOne(f,'media'))}save();activity(`Added ${files.length} media file(s)`);render()}
async function addMemory(){let files=[...($('#memFiles')?.files||[])],photos=[];let results=await Promise.allSettled(files.map(f=>uploadOne(f,'memories')));results.forEach(r=>{if(r.status==='fulfilled'){arr('media').unshift(r.value);photos.push(r.value.url)}});if(files.length&&!photos.length){toast('Photos could not be uploaded. Please try again.');return}arr('memories').unshift({id:id(),tripId:selectedTrip,owner:uid,title:$('#memTitle')?.value||'Memory',date:$('#memDate')?.value||'',text:$('#memText')?.value||'',photos,createdAt:Date.now()});save();activity(`Added memory with ${photos.length} photo${photos.length===1?'':'s'}`);if(photos.length<files.length)toast(`${photos.length} of ${files.length} photos saved. Try the missing photos again.`);render()}
async function signIn(){try{if(!window.firebase||!firebase.apps.length)initFirebase();if(!window.firebase||!firebase.apps.length){toast('Firebase is not loaded yet; local Admin saving is active');return}let e=$('#loginEmail').value.trim(),p=$('#loginPass').value;if(!e||!p){toast('Enter email and password');return}await firebase.auth().signInWithEmailAndPassword(e,p);toast('Signed in as Admin')}catch(err){console.error(err);toast(err.message||'Login failed')}}
async function signUpAdmin(){try{if(!window.firebase||!firebase.apps.length)initFirebase();if(!window.firebase||!firebase.apps.length){toast('Firebase is not loaded yet; local Admin saving is active');return}let e=$('#loginEmail').value.trim(),p=$('#loginPass').value;if(!e||!p){toast('Enter email and password');return}await firebase.auth().createUserWithEmailAndPassword(e,p);role='Admin';localStorage.setItem('ofa-role','Admin');toast('Admin login created')}catch(err){console.error(err);toast(err.message||'Could not create login')}}
async function signOut(){try{if(window.firebase&&firebase.auth)await firebase.auth().signOut();fb=false;setIdentity(null);toast('Signed out — still Admin on this device');render()}catch(e){toast('Signed out locally')}}
function requestPush(){try{if(!('Notification'in window)||typeof Notification.requestPermission!=='function'){toast('Notifications not supported');return}Notification.requestPermission().then(p=>toast(p==='granted'?'Notifications enabled':'Notifications not enabled')).catch(()=>toast('Notifications not enabled'))}catch(e){toast('Notifications not supported on this browser')}}
function markRead(){arr('notifications').filter(n=>!n.user||n.user===uid).forEach(n=>n.read=true);updateAppBadge(0);save();render()}
function clearMyNotifications(){data.notifications=arr('notifications').filter(n=>n.user&&n.user!==uid);updateAppBadge(0);save();render()}
function changeAdminCode(){if(!canAdmin())return;let c=$('#newAdminCode')?.value?.trim();if(!/^\d{4,12}$/.test(c||'')){toast('Use a 4–12 digit code');return}st().adminCode=c;save();toast('Admin code changed')}
function setRsvp(status){let name=currentPersonName(),rows=arr('rsvps');let existing=rows.find(r=>r.tripId===selectedTrip&&r.user===uid);if(existing)Object.assign(existing,{status,name,updatedAt:Date.now()});else rows.unshift({id:id(),tripId:selectedTrip,user:uid,owner:uid,name,status,createdAt:Date.now()});save();activity('Updated RSVP');render()}
function install(){if(deferredInstall){deferredInstall.prompt();deferredInstall=null}else toast('Use browser menu: Add to Home screen')}
function exportData(){let a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(data,null,2)],{type:'application/json'}));a.download='our-family-adventures-backup-9.0.2.json';a.click()}
function importClick(){$('#importFile').click();$('#importFile').onchange=e=>{let f=e.target.files[0];let r=new FileReader();r.onload=()=>{data=Object.assign(blank(),JSON.parse(r.result));migrate(false);save();toast('Backup imported')};r.readAsText(f)}}
async function loadTripWeather(){let box=document.querySelectorAll('#tripWeather');if(!box.length)return;let t=trip(),place=t?.location||t?.name||'York PA';try{let r=await fetch(`https://wttr.in/${encodeURIComponent(place)}?format=j1`);if(!r.ok)throw new Error('weather');let j=await r.json(),c=j.current_condition?.[0]||{},days=(j.weather||[]).slice(0,4);let html=`<div class="weatherNow"><b>${escape(place)}</b><strong>${escape(c.temp_F||'--')}°F</strong><span>${escape(c.weatherDesc?.[0]?.value||'')}</span><small>Feels like ${escape(c.FeelsLikeF||'--')}° · Humidity ${escape(c.humidity||'--')}%</small></div><div class="forecastDays">${days.map(d=>`<div><b>${new Date(d.date+'T12:00:00').toLocaleDateString(undefined,{weekday:'short'})}</b><span>${escape(d.maxtempF||'--')}° / ${escape(d.mintempF||'--')}°</span><small>${escape(d.hourly?.[4]?.weatherDesc?.[0]?.value||'Forecast')}</small></div>`).join('')}</div>`;box.forEach(x=>x.innerHTML=html)}catch(e){box.forEach(x=>x.innerHTML=`<p class="muted">Live weather could not load. Confirm the trip destination and internet connection.</p><a class="buttonLike" target="_blank" rel="noopener" href="https://www.google.com/search?q=${encodeURIComponent(place+' weather')}">Open weather forecast</a>`)}}
function savedScrapMarkup(s){let objs=s.objects||[],bg=escape(s.background||'seaglass');return `<div class="savedScrapCanvas ${bg}">${objs.map(o=>`<div class="savedScrapObj ${o.sticker?'stickerObj':''}" style="left:${Number(o.x)||0}px;top:${Number(o.y)||0}px;width:${Number(o.w)||100}px;height:${Number(o.h)||100}px;z-index:${Number(o.z)||1};transform:rotate(${Number(o.rot)||0}deg)"><div class="scrapContent frame-${escape(o.frame||'nofill')} cutout-${escape(o.cutout||(['heart','scallop','flower'].includes(o.frame)?o.frame:'none'))}" style="--frame-color:${escape(o.frameColor||'#d8b46a')}">${o.img?`<img src="${escape(o.img)}" style="object-fit:${escape(o.fit||'cover')};transform:scale(${Number(o.zoom)||1})">`:`<span style="font-size:${Math.max(24,Math.min(Number(o.w)||72,Number(o.h)||72)*.68)}px">${escape(o.text||'')}</span>`}</div></div>`).join('')}</div>`}
function setScrapBg(v){let c=$('#scrapCanvas'); if(c){c.className='scrapCanvas '+v}}
function scrapObjs(){window.scrapObjs=window.scrapObjs||[];return window.scrapObjs}
function drawScrap(){let c=$('#scrapCanvas');if(!c)return;c.innerHTML='';scrapObjs().forEach(o=>{let d=document.createElement('div');d.className='scrapObj'+(o.sticker?' stickerObj':'');Object.assign(d.style,{left:o.x+'px',top:o.y+'px',width:o.w+'px',height:o.h+'px',zIndex:o.z||1,transform:`rotate(${o.rot||0}deg)`});let inner=document.createElement('div');inner.className='scrapContent frame-'+(o.frame||'nofill')+' cutout-'+(o.cutout||(['heart','scallop','flower'].includes(o.frame)?o.frame:'none'));inner.style.setProperty('--frame-color',o.frameColor||'#d8b46a');if(o.img)inner.innerHTML=`<img src="${o.img}" alt="photo" style="object-fit:${o.fit||'cover'};transform:scale(${o.zoom||1})">`;else inner.innerHTML=`<span contenteditable="${o.sticker?'false':'true'}" style="font-size:${Math.max(24,Math.min(o.w,o.h)*.68)}px">${escape(o.text||'Text')}</span>`;d.appendChild(inner);d.insertAdjacentHTML('beforeend',['nw','n','ne','e','se','s','sw','w'].map(h=>`<i class="resizeHandle ${h}" data-h="${h}"></i>`).join('')+`<i class="rotateHandle" data-rotate="1">↻</i>`);d.onclick=()=>{window.selectedScrapObj=o;document.querySelectorAll('.scrapObj').forEach(x=>x.classList.remove('selected'));d.classList.add('selected')};c.appendChild(d);makeDrag(d,o)})}
function makeDrag(el,o){let start,mode='move',handle='';el.onpointerdown=e=>{handle=e.target.dataset.h||'';mode=e.target.dataset.rotate?'rotate':handle?'resize':'move';let r=el.getBoundingClientRect();start={x:e.clientX,y:e.clientY,ox:o.x,oy:o.y,ow:o.w,oh:o.h,cx:r.left+r.width/2,cy:r.top+r.height/2};o.z=Date.now();window.selectedScrapObj=o;el.classList.add('selected');el.setPointerCapture(e.pointerId);e.preventDefault()};el.onpointermove=e=>{if(!start)return;let dx=e.clientX-start.x,dy=e.clientY-start.y;if(mode==='rotate'){o.rot=Math.atan2(e.clientY-start.cy,e.clientX-start.cx)*180/Math.PI+90;el.style.transform=`rotate(${o.rot}deg)`;return}if(mode==='move'){o.x=Math.max(0,start.ox+dx);o.y=Math.max(0,start.oy+dy)}else{if(handle.includes('e'))o.w=Math.max(40,start.ow+dx);if(handle.includes('s'))o.h=Math.max(40,start.oh+dy);if(handle.includes('w')){o.w=Math.max(40,start.ow-dx);o.x=start.ox+dx}if(handle.includes('n')){o.h=Math.max(40,start.oh-dy);o.y=start.oy+dy}}Object.assign(el.style,{left:o.x+'px',top:o.y+'px',width:o.w+'px',height:o.h+'px'})};el.onpointerup=()=>{start=null}}
function addScrapText(){scrapObjs().push({text:'Family memory',x:60,y:60,w:190,h:90,z:1});drawScrap()}
function addSticker(s){scrapObjs().push({text:s,x:90,y:90,w:72,h:72,z:1,sticker:true,frame:'nofill'});drawScrap()}
function addSelectedPhoto(){let sel=[...document.querySelectorAll('input[name="scrapPhoto"]:checked')].map(o=>o.value);let added=0;sel.forEach((mid,i)=>{let m=arr('media').find(x=>x.id===mid);if(m&&m.url){scrapObjs().push({img:m.url,frame:$('#scrapFrame')?.value||'nofill',cutout:$('#scrapCutout')?.value||'none',frameColor:$('#scrapFrameColor')?.value||'#d8b46a',x:40+(i*28),y:60+(i*28),w:210,h:165,z:1,fit:'cover',zoom:1,rot:0});added++}});if(!added){toast('Add photos in Media first');return}drawScrap()}
function toggleAssignment(entity,itemId,name){let x=arr(entity).find(y=>y.id===itemId);if(!x)return;let a=Array.isArray(x.assignedTo)?[...x.assignedTo]:(x.assignedTo?[x.assignedTo]:[]);x.assignedTo=a.includes(name)?a.filter(n=>n!==name):[...a,name];save();activity(`Updated ${entity} responsibility`);render()}
function applyFrame(v){let o=window.selectedScrapObj;if(!o||!o.img){toast('Tap a photo first');return}o.frame=v;drawScrap()}
function applyFrameColor(v){let o=window.selectedScrapObj;if(!o||!o.img){toast('Tap a photo first');return}o.frameColor=v;drawScrap()}
function applyCutout(v){let o=window.selectedScrapObj;if(!o||!o.img){toast('Tap a photo first');return}o.cutout=v;drawScrap()}
function volunteer(entity,itemId){let x=arr(entity).find(y=>y.id===itemId);if(!x)return;let name=currentPersonName();let names=Array.isArray(x.assignedTo)?x.assignedTo:(x.assignedTo?[x.assignedTo]:[]);if(names.includes(name))names=names.filter(n=>n!==name);else names.push(name);x.assignedTo=names;save();activity(`${name} updated responsibility for ${entity}`);render()}
function addCollage(){let imgs=byTrip('media').filter(m=>m.url&&String(m.type||'').startsWith('image')).slice(0,4);if(!imgs.length){toast('Add photos in Media first');return}let spots=[[40,40],[270,40],[40,250],[270,250]];imgs.forEach((m,i)=>scrapObjs().push({img:m.url,frame:'soft',x:spots[i][0],y:spots[i][1],w:210,h:190,z:Date.now()+i,fit:'cover',zoom:1,rot:0}));drawScrap()}
function applyLayout(kind){let photos=scrapObjs().filter(o=>o.img);if(!photos.length){toast('Add photos first');return}let spots=[];if(kind==='grid2')spots=[[35,85,285,260],[360,85,285,260]];else if(kind==='grid4')spots=[[30,55,290,300],[360,55,290,300],[30,390,290,300],[360,390,290,300]];else if(kind==='feature')spots=[[55,55,570,440],[55,525,175,170],[252,525,175,170],[450,525,175,170]];else if(kind==='collage')spots=[[45,60,330,260],[330,120,300,240],[80,350,280,230],[345,410,285,230]];else return;photos.slice(0,spots.length).forEach((o,i)=>{let [x,y,w,h]=spots[i];Object.assign(o,{x,y,w,h,rot:kind==='collage'?[-5,4,3,-4][i]||0:0,z:Date.now()+i})});drawScrap()}
function sendBackward(){let o=window.selectedScrapObj;if(!o){toast('Tap an object first');return}o.z=Math.max(1,(o.z||1)-100000);drawScrap()}
function deleteScrapObject(){let o=window.selectedScrapObj;if(!o){toast('Tap an object first');return}window.scrapObjs=scrapObjs().filter(x=>x!==o);window.selectedScrapObj=null;drawScrap()}
function canvasZoom(f){let c=$('#scrapCanvas');if(!c)return;let z=Number(c.dataset.zoom||1)*f;z=Math.min(2.5,Math.max(.35,z));c.dataset.zoom=z;c.style.transform=`scale(${z})`;c.style.transformOrigin='top left'}
function exportScrapPDF(){let c=$('#scrapCanvas');if(!c)return;let w=window.open('','_blank');if(!w){toast('Allow popups to export PDF');return}let clone=c.cloneNode(true);clone.querySelectorAll('.resizeHandle,.rotateHandle').forEach(h=>h.remove());clone.querySelectorAll('[contenteditable]').forEach(x=>x.removeAttribute('contenteditable'));w.document.write(`<!doctype html><html><head><title>Scrapbook PDF</title><link rel="stylesheet" href="${location.origin+location.pathname.replace(/[^/]+$/,'')}style.css"><style>body{margin:0;background:white}.scrapCanvas{margin:0;box-shadow:none;transform:none!important}@page{size:letter portrait;margin:.25in}.handle{display:none}</style></head><body>${clone.outerHTML}<script>onload=()=>setTimeout(()=>print(),400)<\/script></body></html>`);w.document.close()}
function saveScrapbook(){arr('scrapbooks').unshift({id:id(),tripId:selectedTrip,owner:uid,title:'Scrapbook page',background:$('#scrapBg')?.value||'seaglass',objects:JSON.parse(JSON.stringify(scrapObjs())),locked:true,createdAt:Date.now()});window.scrapObjs=[];save();activity('Saved scrapbook page');render()}
function sendChat(){let text=$('#chatText')?.value?.trim(); if(!text)return;arr('chats').unshift({id:id(),tripId:selectedTrip||'',text,user:uid,userName:canAdmin()?'Melissa/Admin':'Family',createdAt:Date.now()});save();notify('New group chat message');render()}
function castVote(voteId){let v=arr('votes').find(x=>x.id===voteId);if(!v)return;let name=currentPersonName(),email=localStorage.getItem('ofa-email')||'',identity=uid||email||name;arr('votes').filter(x=>x.tripId===v.tripId&&x.category===v.category).forEach(x=>{x.voterIds=(x.voterIds||[]).filter(i=>i!==identity&&i!==uid&&i!==email);x.voters=(x.voters||[]).filter(n=>n!==name)});v.voterIds=v.voterIds||[];v.voters=v.voters||[];if(!v.voterIds.includes(identity))v.voterIds.push(identity);if(!v.voters.includes(name))v.voters.push(name);save();activity('Changed vote to '+(v.name||'selected option'));toast('Your vote was updated');render()}

async function addProfile(){let obj={id:id(),name:$('#f_name')?.value||'',email:$('#f_email')?.value||'',phone:$('#f_phone')?.value||'',owner:uid,createdAt:Date.now()};let f=$('#profilePhoto')?.files?.[0];if(f)obj.photo=await fileToDataURL(f);let existing=arr('people').find(p=>(obj.email&&p.email===obj.email)||p.owner===uid&&p.name===obj.name);if(existing)Object.assign(existing,obj,{id:existing.id});else arr('people').unshift(obj);save();activity('Updated profile');render()}
function editProfile(pid){let p=arr('people').find(x=>x.id===pid);if(!p)return;let name=prompt('Name',p.name||'');if(name===null)return;let email=prompt('Email',p.email||'');if(email===null)return;let phone=prompt('Phone',p.phone||'');if(phone===null)return;Object.assign(p,{name,email,phone,updatedAt:Date.now()});save();activity('Updated profile');render()}
function zoomPhoto(factor){let o=window.selectedScrapObj;if(!o||!o.img){toast('Tap a photo first');return}o.zoom=(o.zoom||1)*factor;drawScrap()}
function cropPhoto(){let o=window.selectedScrapObj;if(!o||!o.img){toast('Tap a photo first');return}o.fit=o.fit==='cover'?'contain':'cover';drawScrap()}


async function changeProfilePhoto(pid,file){let p=arr('people').find(x=>x.id===pid);if(!p||!file)return;p.photo=await fileToDataURL(file);p.updatedAt=Date.now();save();activity('Changed profile photo');render()}
function setTheme(v){st().theme=v;save();render()}
function setNotify(k,v){st().notifications[k]=v;save();toast('Settings saved')}
function rotatePhoto(){let o=window.selectedScrapObj;if(!o){toast('Tap an object first');return}o.rot=((o.rot||0)+15)%360;drawScrap()}
function bringForward(){let o=window.selectedScrapObj;if(!o){toast('Tap an object first');return}o.z=Date.now();drawScrap()}
function selectedMsgPeople(){return [...document.querySelectorAll('input[name="msgPeople"]:checked')].map(i=>arr('people').find(p=>p.id===i.value)).filter(Boolean)}
function sendGroupText(){let ps=selectedMsgPeople(),body=encodeURIComponent($('#msgBody')?.value||'');let nums=ps.map(p=>(p.phone||'').replace(/[^0-9+]/g,'')).filter(Boolean);if(!nums.length){toast('Select people with phone numbers');return}location.href=`sms:${nums.join(',')}?&body=${body}`}
function sendGroupEmail(){let ps=selectedMsgPeople(),body=encodeURIComponent($('#msgBody')?.value||''),emails=ps.map(p=>p.email).filter(Boolean);if(!emails.length){toast('Select people with email addresses');return}location.href=`mailto:${emails.join(',')}?subject=Our Family Adventures&body=${body}`}
function toggleLock(area){if(!canAdmin())return;locks()[area]=!locks()[area];save();render()}

window.app={enter,signIn,signUpAdmin,signOut,go:setRoute,pickTrip:v=>{selectedTrip=v;render()},add,del,dedupe,uploadMedia,addMemory,requestPush,markRead,clearMyNotifications,changeAdminCode,setRsvp,install,exportData,importClick,migrateNow:()=>{migrate(false);save();toast('Migration complete')},notify:()=>setRoute('notifications'),toggleDone:(e,i)=>{let x=arr(e).find(y=>y.id===i);if(x){x.done=!x.done;save();render()}},addScrapText,addSticker,addSelectedPhoto,saveScrapbook,setScrapBg,sendChat,castVote,clearActivity:()=>{if(confirm('Clear activity log?')){data.activity=[];save();render()}},clearChat:()=>{if(confirm('Clear chat messages?')){data.chats=[];save();render()}},addProfile,editProfile,zoomPhoto,cropPhoto,changeProfilePhoto,setTheme,setNotify,requestPush,toggleQuickChat,sendQuickChat,applyLayout,rotatePhoto,bringForward,sendBackward,deleteScrapObject,canvasZoom,addCollage,exportScrapPDF,volunteer,toggleAssignment,applyFrame,applyFrameColor,applyCutout,sendGroupText,sendGroupEmail,toggleLock};
setup();
})();
